<template><el-card><template #header>资产版本管理</template><DataTable :data="rows"><el-table-column prop="assetName" label="资产名称" min-width="220"/><el-table-column prop="version" label="版本"/><el-table-column label="当前"><template #default="s"><el-tag v-if="s.row.current" type="success">当前版本</el-tag></template></el-table-column><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column prop="effectiveDate" label="生效日期"/><el-table-column prop="expireDate" label="失效日期"/><el-table-column prop="publisher" label="发布人"/><el-table-column prop="publishedAt" label="发布时间"/><el-table-column label="操作" width="220"><template #default="s"><el-button link type="primary" @click="compare=s.row">版本对比</el-button><el-button link @click="rollback(s.row)">回滚</el-button><el-button link type="danger" @click="s.row.status='deprecated'">废止</el-button></template></el-table-column></DataTable><el-dialog v-model="open" title="版本对比" width="760"><div class="two-col"><el-card>变更前：旧版本材料清单、规则阈值。</el-card><el-card>变更后：更新有效期与容量阈值，补充证据锚点。</el-card></div></el-dialog></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { versions } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; import StatusTag from '@/components/StatusTag.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(versions))); const compare=ref<any>(); const open=computed({get:()=>!!compare.value,set:v=>{if(!v)compare.value=null}}); function rollback(r:any){rows.value.filter(i=>i.assetName===r.assetName).forEach(i=>i.current=false); r.current=true; r.status='published'}</script>
